const icalData = $input.item.json.data;

// Extract all VEVENT blocks
const eventBlocks = icalData.match(/BEGIN:VEVENT[\s\S]*?END:VEVENT/g) || [];

const events = eventBlocks.map(block => {
  const getField = (field) => {
    const match = block.match(new RegExp(`${field}:(.*?)(?:\n[A-Z]|\nEND:)`, 's'));
    return match ? match[1].replace(/\n /g, '').trim() : '';
  };

  const parseDate = (dateStr) => {
    // Format: 20240523T090033Z
    const year = dateStr.slice(0, 4);
    const month = dateStr.slice(4, 6);
    const day = dateStr.slice(6, 8);
    const hour = dateStr.slice(9, 11);
    const min = dateStr.slice(11, 13);
    return new Date(`${year}-${month}-${day}T${hour}:${min}:00Z`);
  };

  const startStr = getField('DTSTART');
  const endStr = getField('DTEND');
  const summary = getField('SUMMARY');
  const description = getField('DESCRIPTION');
  const location = getField('LOCATION');
  const uid = getField('UID').split('@')[0];

  // Extract luma URL from description
  const lumaUrl = description.match(/https:\/\/luma\.com\/\w+/)?.[0] || '';

  return {
    title: summary,
    start: parseDate(startStr),
    end: parseDate(endStr),
    description: description.split('\n\n')[0], // First paragraph only
    location: location,
    url: lumaUrl,
    uid: uid
  };
});

// Sort by date (newest first for display)
const sorted = events.sort((a, b) => b.start - a.start);

return [{ json: { events: sorted } }];

const events = $input.item.json.events;

const now = new Date();
const upcoming = events.filter(e => new Date(e.start) >= now);
const past = events.filter(e => new Date(e.start) < now);

const formatDate = (dateStr) => {
  const date = new Date(dateStr);
  return date.toLocaleDateString('en-US', { 
    year: 'numeric', 
    month: 'long', 
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    timeZoneName: 'short'
  });
};

const formatDateShort = (dateStr) => {
  const date = new Date(dateStr);
  return date.toLocaleDateString('en-US', { 
    year: 'numeric', 
    month: 'long', 
    day: 'numeric'
  });
};

let jsx = `export const lumaEventsData = {\n`;
jsx += `  lastUpdated: "${new Date().toISOString()}",\n`;
jsx += `  upcoming: [\n`;

upcoming.forEach((event, idx) => {
  jsx += `    {\n`;
  jsx += `      title: "${event.title.replace(/"/g, '\\"')}",\n`;
  jsx += `      date: "${formatDate(event.start)}",\n`;
  jsx += `      location: "${event.location.replace(/"/g, '\\"')}",\n`;
  jsx += `      url: "${event.url}",\n`;
  jsx += `      description: "${event.description.split('\\n\\n')[0].replace(/"/g, '\\"').replace(/\n/g, ' ')}"\n`;
  jsx += `    }${idx < upcoming.length - 1 ? ',' : ''}\n`;
});

jsx += `  ],\n`;
jsx += `  past: [\n`;

past.forEach((event, idx) => {
  jsx += `    {\n`;
  jsx += `      title: "${event.title.replace(/"/g, '\\"')}",\n`;
  jsx += `      date: "${formatDateShort(event.start)}",\n`;
  jsx += `      location: "${event.location.replace(/"/g, '\\"')}",\n`;
  jsx += `      url: "${event.url}"\n`;
  jsx += `    }${idx < past.length - 1 ? ',' : ''}\n`;
});

jsx += `  ]\n`;
jsx += `};\n`;

return [{ 
  json: { 
    content: jsx,
    filename: 'lumaEventsData.jsx'
  } 
}];

const events = $input.first().json.events;
const html = $input.last().json.data;

// Extract __NEXT_DATA__ which has event images
const match = html.match(/<script id="__NEXT_DATA__" type="application\/json">(.*?)<\/script>/s);

let imageMap = {};

if (match) {
  try {
    const nextData = JSON.parse(match[1]);
    const pageEvents = nextData.props?.pageProps?.events || [];

    // Map images to events by UID
    pageEvents.forEach(e => {
      if (e.cover_url || e.image_url) {
        imageMap[e.api_id] = e.cover_url || e.image_url;
      }
    });
  } catch (e) {
    // If parsing fails, continue without images
  }
}

// Add images to parsed events
const eventsWithImages = events.map(event => ({
  ...event,
  image: imageMap[event.uid] || null
}));

return [{ json: { events: eventsWithImages } }];
